// FabricOperationCreateBulk is the builder for creating many FabricOperation entities in bulk.
type FabricOperationCreateBulk struct {
	config
	err      error
	builders []*FabricOperationCreate
}

// Save creates the FabricOperation entities in the database.
func (focb *FabricOperationCreateBulk) Save(ctx context.Context) ([]*FabricOperation, error) {
	if focb.err != nil {
		return nil, focb.err
	}
	specs := make([]*sqlgraph.CreateSpec, len(focb.builders))
	nodes := make([]*FabricOperation, len(focb.builders))
	mutators := make([]Mutator, len(focb.builders))
	for i := range focb.builders {
		func(i int, root context.Context) {
			builder := focb.builders[i]
			builder.defaults()
			var mut Mutator = MutateFunc(func(ctx context.Context, m Mutation) (Value, error) {
				mutation, ok := m.(*FabricOperationMutation)
				if !ok {
					return nil, fmt.Errorf("unexpected mutation type %T", m)
				}
				if err := builder.check(); err != nil {
					return nil, err
				}
				builder.mutation = mutation
				var err error
				nodes[i], specs[i] = builder.createSpec()
				if i < len(mutators)-1 {
					_, err = mutators[i+1].Mutate(root, focb.builders[i+1].mutation)
				} else {
					spec := &sqlgraph.BatchCreateSpec{Nodes: specs}
					// Invoke the actual operation on the latest mutation in the chain.
					if err = sqlgraph.BatchCreate(ctx, focb.driver, spec); err != nil {
						if sqlgraph.IsConstraintError(err) {
							err = &ConstraintError{msg: err.Error(), wrap: err}
						}
					}
				}
				if err != nil {
					return nil, err
				}
				mutation.id = &nodes[i].ID
				mutation.done = true
				return nodes[i], nil
			})
			for i := len(builder.hooks) - 1; i >= 0; i-- {
				mut = builder.hooks[i](mut)
			}
			mutators[i] = mut
		}(i, ctx)
	}
	if len(mutators) > 0 {
		if _, err := mutators[0].Mutate(ctx, focb.builders[0].mutation); err != nil {
			return nil, err
		}
	}
	return nodes, nil
}

// SaveX is like Save, but panics if an error occurs.
func (focb *FabricOperationCreateBulk) SaveX(ctx context.Context) []*FabricOperation {
	v, err := focb.Save(ctx)
	if err != nil {
		panic(err)
	}
	return v
}

// Exec executes the query.
func (focb *FabricOperationCreateBulk) Exec(ctx context.Context) error {
	_, err := focb.Save(ctx)
	return err
}

// ExecX is like Exec, but panics if an error occurs.
func (focb *FabricOperationCreateBulk) ExecX(ctx context.Context) {
	if err := focb.Exec(ctx); err != nil {
		panic(err)
	}
}
